import pandas as pd
import altair as alt

source = pd.DataFrame({
    'age': ['12', '32', '43', '54', '32', '32', '12','20','44','24'],
    'gender': ['m','m','f','f','f','m','f','m','f','m']
})

alt.Chart(source).transform_joinaggregate(
    total='count(*)',
    groupby=['gender']
).transform_calculate(
    pct='1 / datum.total'
).mark_bar().encode(
    alt.X('age:Q', bin=True),
    alt.Y('sum(pct):Q', axis=alt.Axis(format='%')),
    color='gender'
)

import pandas as pd
import yfinance as yf
import concurrent.futures

data = pd.read_csv('data/stock_list.csv')

def getPR(symbol):
    sn = None
    pr = None
    try:
        stock = yf.Ticker(symbol)
        pr = stock.info['pegRatio']
        sn = stock.info['shortName']
    except Exception:
        pass
    return (sn, pr)


with concurrent.futures.ThreadPoolExecutor() as executor:
    futures = {executor.submit(getPR, sym): sym for sym in data['Symbol']}
    for future in concurrent.futures.as_completed(futures):
        sn, pr = future.result()
        if sn:
            print(f'{sn} : {pr}')

